#include "ucl.h"
#include "ucl_internal.h"
#include <stdio.h>
int main() {
    struct ucl_parser *parser = ucl_parser_new(UCL_PARSER_KEY_LOWERCASE);
    const char *input = "{\"key\": \"value\"}";
    ucl_parser_add_string(parser, input, 0);
    if (ucl_parser_get_error(parser)) {
        fprintf(stderr, "Parse error: %s\n", ucl_parser_get_error(parser));
        return 1;
    }
    ucl_object_t *obj = ucl_parser_get_object(parser);
    unsigned char *emitted = ucl_object_emit(obj, UCL_EMIT_CONFIG);
    printf("Emitted: [%s]\n", emitted);
    free(emitted);
    ucl_object_unref(obj);
    ucl_parser_free(parser);
    return 0;
}
